") db.session.commit() else: app.logger.warning(f"No Statistics entry found for date {date} when deleting row {row_id}") # Удаляем запись из таблицы db.session.delete(row) db.session.commit() # Уменьшаем счетчик DL, если запись содержала DL-номер if row.dl_number: dl_counter = DLCounter.query.filter_by(date=date).first() if dl_counter and dl_counter.counter > 0: dl_counter.counter -= 1 db.session.commit() # Отправляем сообщение в очередь для обновления клиентов update_queue.put(json.dumps({"type": "delete", "date": date, "id": row.id})) return jsonify({'status': 'success'}) except Exception as e: db.session.rollback() app.logger.error(f"Ошибка в delete_row: {str(e)}") return jsonify({'status': 'error', 'message': str(e)}), 500 @app.route('/', methods=['GET', 'POST']) def main(): if request.method == 'POST': worker = request.form.get('worker') name = request.form.get('name') # Сохраняем информацию о входе user = User.query.filter_by(username=name).first() if not user: user = User(username=name) db.session.add(user) login_history = LoginHistory(user=user) db.session.add(login_history) db.session.commit() resp = make_response(redirect('/welcome')) resp.set_cookie('worker', worker) resp.set_cookie('name', name) return resp return render_template('main.html') @app.route('/get_current_dl', methods=['GET']) def get_current_dl(): date = request.args.get('date') if not date: return jsonify({"status": "error", "message": "Дата обязательна"}), 400 dl_counter = DLCounter.query.filter_by(date=date).first() if dl_counter: return jsonify({"status": "success", "current_dl": dl_counter.counter}) else: return jsonify({"status": "error", "message": "Счетчик DL не инициализирован для этой даты"}), 404 @app.route('/welcome') def welcome(): worker = request.cookies.get('worker') name = request.cookies.get('name') if not worker or not name: return redirect('/') current_time = datetime.utcnow() devices = [device.to_dict(current_time=current_time) for device in Device.query.order_by(Device.