port_excel', methods=['POST']) def import_excel(): try: # Check if a file is provided if 'file' not in request.files: return jsonify({"status": "error", "message": "No file provided"}), 400 # Get the uploaded file file = request.files['file'] # Check the file extension for security reasons if not file.filename.endswith('.xlsx') and not file.filename.endswith('.xls'): return jsonify({"status": "error", "message": "File type not allowed"}), 400 # Read the Excel file into a DataFrame df = pd.read_excel(file) # Define the fields expected in the Excel file required_columns = ['Время отправки', 'Номер', 'Serial', 'Графа', 'Имя отправителя'] # Check if all required columns are in the DataFrame if not all(col in df.columns for col in required_columns): return jsonify({"status": "error", "message": f"Missing required columns. Required columns are: {', '.join(required_columns)}"}), 400 # Get current date current_date = datetime.now().date().strftime("%Y-%m-%d") # Iterate over DataFrame rows and insert data into the database for _, row in df.iterrows(): new_row = TableRow( date=current_date, timestamp=row['Время отправки'], number=row['Номер'], serial=row['Serial'], dl_number=row['Графа'], worker_name=row['Имя отправителя'], row_number='', # Will be calculated later pack_time=row['Время отправки'], # Default value arma_type='RPA', # Default value dateshipment=row['Время отправки'], aktshipment='-', # Default value bad_recovery=row.get('bad_recovery', False) , ) db.session.add(new_row) db.session.commit() # Update row numbers rows_of_day = TableRow.query.filter_by(date=current_date).order_by(TableRow.id).all() for idx, row in enumerate(rows_of_day, 1): row.row_number = str(idx) db.session.commit() return jsonify({"status": "success", "message": "Data imported successfully"}) except Exception as e: db.session.rollback() app.logger.error(f"Error during Excel import: {str(e)}") # Логируем ошибку return jsonify({"status": "error", "message": str(e)}), 500 @app.route('/delete_import