eet1') # Настраиваем форматирование workbook = writer.book worksheet = writer.sheets['Sheet1'] # Автоматическая ширина столбцов for idx, col in enumerate(df.columns): series = df[col] max_len = max( series.astype(str).map(len).max(), len(str(col)) ) + 2 worksheet.set_column(idx, idx, max_len) output.seek(0) return send_file( output, mimetype='application/vnd.openxmlformats-officedocument.spreadsheetml.sheet', as_attachment=True, download_name='RPA_export.xlsx' ) except Exception as e: print(f"Export error: {str(e)}") return jsonify({"error": str(e)}), 500 @app.route('/get_duplicates') def get_duplicates(): try: # Получим все строки из таблицы только с типом "RPA" rows = TableRow.query.filter_by(arma_type='RPA').all() # Хранилища для множества значений numbers = {} serials = {} dl_numbers = {} # Собираем все значения и их индексы data = [] for row in rows: row_data = { 'id': row.id, 'row_number': row.row_number, 'timestamp': row.timestamp, 'number': row.number, 'serial': row.serial, 'dl_number': row.dl_number, 'worker_name': row.worker_name, 'pack_time': row.pack_time, 'arma_type': row.arma_type, 'dateshipment': row.dateshipment, 'aktshipment': row.aktshipment, 'bad_recovery': row.bad_recovery, } data.append(row_data) if row.number: clean_number = ''.join(filter(str.isdigit, row.number)) if clean_number in numbers: numbers[clean_number].append(len(data) - 1) else: numbers[clean_number] = [len(data) - 1] if row.serial: clean_serial = ''.join(filter(str.isdigit, row.serial)) if clean_serial in serials: serials[clean_serial].append(len(data) - 1) else: serials[clean_serial] = [len(data) - 1] if row.dl_number: clean_dl_number = ''.join(filter(str.isdigit, row.dl_number)) if clean_dl_number in dl_numbers: dl_numbers[clean_dl_number].append(len(data) - 1) else: dl_numbers[clean_dl_number] = [len(data) - 1] # Фильтруем только реальные дубликаты duplicate_numbers = {k: v for k, v in numbers.items() if len(v) > 1} duplicate_serials = {k: v for k, v in serials.items() if len(v) > 1} duplicate_dl_numbers = {k: v for k, v in dl_numbers.items() if len(v) > 1} duplicates = { "numbers": duplicate_numbers, "serials": duplicate_serials, "dl_numbers": duplicate_dl_numbers } # Сохраняем индексы всех уникальных дубликатов duplicate_indices = set() for indices in duplicate_numbers.values(): duplicate_indices.update(indices) for indices in duplicate_serials.values(): duplicate_indices.update(indices) for indices in duplicate_dl_numbers.values(): duplicate_indices.update(indices) # Отбираем только дубликаты duplicates_data = [data[idx] for idx in duplicate_indices] return jsonify({ "status": "success", "data": duplicates_data, "duplicates": duplicates }) except Exception as e: return jsonify({"status": "error", "message": str(e)}) @app.route('/get_total_rpa_count', methods=['GET']) def get_total_rpa_count(): try: # Count the total number of RPA records total_rpa_count = TableRow.query.filter_by(arma_type='RPA').count() return jsonify({"status": "success", "total_rpa_count": total_rpa_count}) except Exception as e: return jsonify({"status": "error", "message": str(e)}), 500 def ping_device(ip_address): try: # Determine the OS and use appropriate ping command param = '-n' if platform.system().lower() == 'windows' else '-c' command = ['ping', param, '1', ip_address] result = subprocess.run(command, capture_output=True, text=True) # Check if the word "unreachable" is in the output, which indicates failure if "unreachable" in result.stdout: return False elif result.returncode == 0: return True else: return False except Exception as e: print(f"An error occurred while pinging {ip_address}: {e}") return False @app.route('/ping_arm1') def ping_arm1(): ip_address = "192.168.50.108" is_online = ping_device(ip_address) status = 'online' if is_online else 'offline' app.logger.debug(f"Ping status for {ip_address}: {status}") return jsonify({"status": status}) if __name__ == '__main__': with app.app_context(): db.create_all() create_devices() logging.disable(logging.CRITICAL) os.system('title СЕРВЕР') app.run(host='192.168.0.234', port=80, debug=True) #192.168.50.99 let isEditing = false; let isRPAFilterActive = false; let isShowingDuplicates = false; let searchTimeout; let lastUpdateTime = 0; let totalRPARecords = 0; const updateInterval = 1000; let eventSource; let lastData = null; let isDeleting = false; let fpInstance; let unpackedDaysCache = {}; // Ключи будут в формате 'YYYY-MM', значение - Set дней const deviceSparklines = {}; // Глобальные переменные для отслеживания сортировки let globalSortColumn = null; let globalSortOrder = 'asc'; function getSelectedDate() { return $('#datepicker').val(); } // Функция для получения состояния фильтра function getArmaFilter() { return $('#armaFilter').is(':checked') ? 'RPA' : ''; } function updateTable(force = false, highlightNew = false) { return new Promise((resolve, reject) => { const now = Date.now(); if (!force && now - lastUpdateTime < updateInterval) { resolve(); return; } if (isEditing) { resolve(); return; } if (isEditing || isDeleting) { // Добавляем проверку на isDeleting resolve(); return; } // Проверьте, если фильтр RPA активен, не выполняйте обновление автоматически if (isRPAFilterActive) { resolve(); return; } if (isShowingDuplicates) { resolve(); return; } $.ajax({ url: '/get_table_data', type: 'GET', data: { date: getSelectedDate(), filter_arma: getArmaFilter() }, success: function(response) { var tableBody = $('#tableBody'); // Обновляем содержимое таблицы updateTableContent(response.data, tableBody, highlightNew); // Применяем текущую сортировку if (globalSortColumn !== null) { sortTable(globalSortColumn, globalSortOrder); } updateStatistics(); updateTotalRPARecords(); lastUpdateTime = now; // Проверяем и подсвечиваем дубликаты highlightDuplicates(response.duplicates); // Скрываем окно с общим количеством RPA и восстанавливаем статистические окна resolve(); }, error: function(xhr, status, error) { console.error('Error updating table:', error); reject(error); } })