nt(f"Setting initial DL for date {date}: {initial_number}") # Отладочный вывод dl_counter = DLCounter.query.filter_by(date=date).first() if dl_counter: dl_counter.counter = initial_number print(f"Updated existing counter for {date}") # Отладочный вывод else: dl_counter = DLCounter(date=date, counter=initial_number) db.session.add(dl_counter) print(f"Created new counter for {date}") # Отладочный вывод db.session.commit() return jsonify({ "status": "success", "message": f"DL counter set to {initial_number} for date {date}" }) except Exception as e: print(f"Error in set_initial_dl: {str(e)}") # Отладочный вывод db.session.rollback() return jsonify({ "status": "error", "message": str(e) }) @app.route('/generate_dl', methods=['POST']) def generate_dl(): try: data = request.json row_id = data['id'] date = data['date'] # Получаем или создаем счетчик DL для данной даты dl_counter = DLCounter.query.filter_by(date=date).first() if not dl_counter: return jsonify({"status": "error", "message": "DL counter не инициализирован"}), 400 # Генерируем новый DL номер с использованием префикса dl_prefix = app.config['DL_PREFIX'] # Получаем префикс из конфигурации dl_number = f"{dl_prefix}{dl_counter.counter:06d}" # Находим и обновляем нужную запись по id row = TableRow.query.filter_by(id=row_id, date=date).first() if row: row.dl_number = dl_number dl_counter.counter += 1 # Увеличиваем счетчик # Обновляем статистику генерации statistics = Statistics.query.filter_by(date=date).first() if statistics: statistics.generate_clicks += 1 else: statistics = Statistics(date=date, generate_clicks=1, pack_clicks=0) db.session.add(statistics) db.session.commit() return jsonify({"status": "success", "dl_number": dl_number, "id": row_id}) return jsonify({"status": "error", "message": "Строка не найдена"}), 404 except Exception as e: return jsonify({"status": "error", "message": str(e)}), 500 @app.route('/export_excel', methods=['GET']) def export_excel(): try: date = request.args.get('date') # Загружаем все строки из таблицы для подсчёта дубликатов all_rows = TableRow.query.all() # Подготовка хранилищ для подсчёта дубликатов numbers = {} serials = {} dl_numbers = {} # Подсчёт повторений для всех строк for row in all_rows: if row.number: clean_number = ''.join(filter(str.isdigit, row.number)) if clean_number in numbers: numbers[clean_number].append(row) else: numbers[clean_number] = [row] if row.serial: clean_serial = ''.join(filter(str.isdigit, row.serial)) if clean_serial in serials: serials[clean_serial].append(row) else: serials[clean_serial] = [row] if row.dl_number: clean_dl_number = ''.join(filter(str.isdigit, row.dl_number)) if clean_dl_number in dl_numbers: dl_numbers[clean_dl_number].append(row) else: dl_numbers[clean_dl_number] = [row] # Выделяем строки-дубликаты duplicate_numbers = {k: v for k, v in numbers.items() if len(v) > 1} duplicate_serials = {k: v for k, v in serials.items() if len(v) > 1} duplicate_dl_numbers = {k: v for k, v in dl_numbers.items() if len(v) > 1} # Фильтруем строки для указанной даты query = TableRow.query.filter_by(date=date) rows = query.all() # Подготовка данных с учётом bad_recovery data = [] for row in rows: # Проверка, является ли строка дубликатом bad_recovery = False if row.number: clean_number = ''.join(filter(str.isdigit, row.number)) if clean_number in duplicate_numbers: bad_recovery = True if row.serial: clean_serial = ''.join(filter(str.isdigit, row.serial)) if clean_serial in duplicate_serials: bad_recovery = True if row.dl_number: clean_dl_number = ''.join(filter(str.isdigit, row.dl_number)) if clean_dl_number in duplicate_dl_numbers: bad_recovery = True # Добавляем строку в результат data.append({ 'ID': row.id, 'Row Number': row.row_number, 'Timestamp': row.timestamp, 'Number': row.number, 'Serial': row.serial, 'DL Number': row.dl_number, 'Worker Name': row.worker_name, 'Pack Time': row.pack_time, 'ARMA Type': row.arma_type, 'Date Shipment': row.dateshipment, 'Akt Shipment': row.aktshipment, 'Bad Recovery': bad_recovery, # Передаем вычисленное значение bad_recovery }) # Экспорт данных в Excel output = io.BytesIO() workbook = Workbook(output, {'in_memory': True}) worksheet = workbook.add_worksheet() # Заголовки headers = list(data[0].keys()) for col_num, header in enumerate(headers): worksheet.write(0, col_num, header) # Данные for row_num, row_data in enumerate(data, start=1): for col_num, (key, value) in enumerate(row_data.items()): worksheet.write(row_num, col_num, value) workbook.close() output.seek(0) # Отправка файла return send_file( output, as_attachment=True, download_name=f'export_RPA_{date}.xlsx', mimetype='application/vnd.openxmlformats-officedocument.spreadsheetml.sheet' ) except Exception as e: return jsonify({"status": "error", "message": str(e)}) @app.route('/update_serial', methods=['POST']) def update_serial(): try: data = request.json row_index = int(data['row_index']) new_value = data['new_value'] date = data['date'] rows = TableRow.query.filter_by(date=date).all() if 0 <= row_index < len(rows): row = rows[row_index] row.serial = new_value db.session.commit() return jsonify({"status": "success"}) return jsonify({"status": "error", "message": "Invalid row index"}) except Exception as e: db.session.rollback() return jsonify({"status": "error", "message": str(e)}) def initialize_table_for_date(date): # Проверяем, существуют ли уже записи для этой даты existing = TableRow.query.filter_by(date=date).first() if not existing: # Создаем новую запись только в случае отсутствия данных new_row = TableRow( date=date, row_number=str(1), timestamp=datetime.now().strftime("%Y-%m-%d %H:%M:%S"), number='', serial='', dl_number='', worker_name='', arma_type='', pack_time='', dateshipment='', aktshipment='', bad_recovery='', ) db.session.add(new_row) # Инициализируем статистику для новой даты statistics = Statistics(date=date, generate_clicks=0, pack_clicks=0) db.session.add(statistics) db.session.commit() @app.route('/update_serial_arma', methods=['POST']) def update_serial_arma(): try: data = request.json date = data['date'] serial = data['serial'] arma_type = data['arma_type'] # Создаем новую запись в таблице new_row = TableRow( date=date, serial=serial, arma_type=arma_type, timestamp=datetime.now().strftime("%Y-%m-%d %H:%M:%S") ) db.session.add(new_row) db.session.commit() return jsonify({"status": "success"}) except Exception as e: db.session.rollback() return jsonify({"status": "error", "message": str(e)}), 500 @app.route('/get_statistics') def get_statistics(): try: date = request.args.get('date') app.logger.debug(f"Получен запрос статистики для даты: {date}") # Получаем статистику генерации и упаковки statistics = Statistics.query.filter_by(date=date).first() if not statistics: generate_clicks = 0 pack_clicks = 0 app.logger.debug(f"Статистика для даты {date} не найдена. Установлено значение 0.") else: generate_clicks = statistics.generate_clicks pack_clicks = statistics.pack_clicks app.logger.debug(f"Статистика для даты {date}: Генераций = {generate_clicks}, Упаковок = {pack_clicks}") # Получаем количество записей типа "RPA" rpa_records = TableRow.query.filter_by(date=date, arma_type='RPA').count() app.logger.debug(f"Количество записей типа RPA для даты {date}: {rpa_records}") # Считаем количество записей "RPA" без значения в колонке "Графа" unpacked_clicks = TableRow.query.filter( TableRow.date == date, TableRow.arma_type == 'RPA', TableRow.dl_number == None ).count() # Получаем количество упакованных записей за текущий час current_hour = datetime.now().replace(minute=0, second=0, microsecond=0) next_hour = current_hour + timedelta(hours=1) done_per_hour = TableRow.query.filter( TableRow.date == date, TableRow.arma_type == 'RPA', TableRow.pack_time >= current_hour, TableRow.pack_time < next_hour ).count() return jsonify({ "generate_clicks": generate_clicks, "pack_clicks": pack_clicks, "rpa_records": rpa_records, "unpacked_clicks": unpacked_clicks, "done_per_hour": done_per_hour }) except Exception as e: app.logger.error(f"Ошибка в get_statistics: {str(e)}") return jsonify({ "generate_clicks": 0, "pack_clicks": 0, "rpa_records": 0, "unpacked_clicks": 0, "done_per_hour": 0, "error": str(e) }) @app.route('/delete_row', methods=['POST']) def delete_row(): try: data = request.json row_id = data.get('id') if not row_id: return jsonify({'status': 'error', 'message': 'ID записи не предоставлен'}), 400 row = TableRow.query.get(row_id) if not row: return jsonify({'status': 'error', 'message': 'Запись не найдена'}), 404 date = row.date # Получаем дату записи для обновления статистики # Получаем запись статистики для этой даты statistics = Statistics.query.filter_by(date=date).first() if statistics: # Если запись имела сгенерированный DL номер, уменьшаем generate_clicks if row.dl_number: if statistics.generate_clicks > 0: statistics.generate_clicks -= 1 else: app.logger.warning(f"Attempting to decrement generate_clicks below zero for date {date}") # Если запись была упакована, уменьшаем pack_clicks if row.pack_time: if statistics.pack_clicks > 0: statistics.pack_clicks -= 1 else: app.logger.warning(f"Attempting to decrement pack_clicks below zero for date {date}") db.session.commit() else: app.logger.warning(f"No Statistics entry found for date {date} when deleting row {row_id}") # Удаляем запись из таблицы db.session.delete(row) db.session.commit() # Уменьшаем счетчик DL, если запись содержала DL-номер if row.dl_number: dl_counter = DLCounter.query.filter_by(date=date).first() if dl_counter and dl_counter.counter > 0: dl_counter.counter -= 1 db.session.commit() # Отправляем сообщение в очередь для обновления клиентов update_queue.put(json.dumps({"type": "delete", "date": date, "id": row.id})) return jsonify({'status': 'success'}) except Exception as e: db.session.rollback() app.logger.error(f"Ошибка в delete_row: {str(e)}") return jsonify({'status': 'error', 'message': str(e)}), 500 @app.route('/', methods=['GET', 'POST']) def main(): if request.method == 'POST': worker = request.form.get('worker') name = request.form.get('name') # Сохраняем информацию о входе user = User.query.filter_by(username=name).first() if not user: user = User(username=name) db.session.add(user) login_history = LoginHistory(user=user) db.session.add(login_history) db.session.commit() resp = make_response(redirect('/welcome')) resp.set_cookie('worker', worker) resp.set_cookie('name', name) return resp return render_template('main.html') @app.route('/get_current_dl', methods=['GET']) def get_current_dl(): date = request.args.get('date') if not date: return jsonify({"status": "error", "message": "Дата обязательна"}), 400 dl_counter = DLCounter.query.filter_by(date=date).first() if dl_counter: return jsonify({"status": "success", "current_dl": dl_counter.counter}) else: return jsonify({"status": "error", "message": "Счетчик DL не инициализирован для этой даты"}), 404 @app.route('/welcome') def welcome(): worker = request.cookies.get('worker') name = request.cookies.get('name') if not worker or not name: return redirect('/') current_time = datetime.utcnow() devices = [device.to_dict(current_time=current_time) for device in Device.query.order_by(Device.name).all()] current_time_str = current_time.isoformat() # Получаем текущий префикс prefix = Prefix.query.first() dl_prefix = prefix.value if prefix else 'DL' return render_template('welcome.html', name=name, worker=worker, table=table, devices=devices, current_time=current_time_str, dl_prefix=dl_prefix) @app.route('/logout') def logout(): resp = make_response(redirect('/')) resp.delete_cookie('worker') resp.delete_cookie('name') return resp @app.route('/get_unpacked_rpa_counts', methods=['GET']) def get_unpacked_rpa_counts(): year = request.args.get('year') month = request.args.get('month') if not year or not month: return jsonify({"status": "error", "message": "Необходимо указать год и месяц"}), 400 try: year = int(year) month = int(month) except ValueError: return jsonify({"status": "error", "message": "Год и месяц должны быть числами"}), 400 # Формируем формат даты для фильтрации month_str = f"{month:02d}" # Запрашиваем количество записей RPA с пустым значением в колонке "Время упаковки" для каждого дня unpacked_counts = TableRow.query.filter( TableRow.date.like(f"{year}-{month_str}-%"), TableRow.arma_type == 'RPA', or_(TableRow.pack_time == None, TableRow.pack_time == '') ).group_by(TableRow.date).with_entities(TableRow.date, func.count(TableRow.id)).all() # Преобразуем результат в словарь unpacked_counts_dict = {date: count for date, count in unpacked_counts} return jsonify({'status': 'success', 'unpacked_counts': unpacked_counts_dict}) @app.route('/get_last_dl_number_all_time', methods=['GET']) def get_last_dl_number_all_time(): # Получаем последнюю запись с максимальным значением DL за всё время last_dl_row = TableRow.query.order_by(TableRow.dl_number.desc()).first() if last_dl_row: last_dl = last_dl_row.dl_number if last_dl and last_dl.startswith('DL'): last_dl_number = int(last_dl[2:]) next_dl_number = last_dl_number + 1 else: next_dl_number = 1 else: next_dl_number = 1 return jsonify({"status": "success", "next_dl_number": next_dl_number}) @app.route('/import_excel', methods=['POST']) def import_excel(): try: # Check if a file is provided if 'file' not in request.files: return jsonify({"status": "error", "message": "No file provided"}), 400 # Get the uploaded file file = request.files['file'] # Check the file extension for security reasons if not file.filename.endswith('.xlsx') and not file.filename.endswith('.xls'): return jsonify({"status": "error", "message": "File type not allowed"}), 400 # Read the Excel file into a DataFrame df = pd.read_excel(file) # Define the fields expected in the Excel file required_columns = ['Время отправки', 'Номер', 'Serial', 'Графа', 'Имя отправителя'] # Check if all required columns are in the DataFrame if not all(col in df.columns for col in required_columns): return jsonify({"status": "error", "message": f"Missing required columns. Required columns are: {', '.join(required_columns)}"}), 400 # Get current date current_date = datetime.now().date().strftime("%Y-%m-%d") # Iterate over DataFrame rows and insert data into the database for _, row in df.iterrows(): new_row = TableRow( date=current_date, timestamp=row['Время отправки'], number=row['Номер'], serial=row['Serial'], dl_number=row['Графа'], worker_name=row['Имя отправителя'], row_number='', # Will be calculated later pack_time=row['Время отправки'], # Default value arma_type='RPA', # Default value dateshipment=row['Время отправки'], aktshipment='-', # Default value bad_recovery=row.get('bad_recovery', False) , ) db.session.add(new_row) db.session.commit() # Update row numbers rows_of_day = TableRow.query.filter_by(date=current_date).order_by(TableRow.id).all() for idx, row in enumerate(rows_of_day, 1): row.row_number = str(idx) db.session.commit() return jsonify({"status": "success", "message": "Data imported successfully"}) except Exception as e: db.session.rollback() app.logger.error(f"Error during Excel import: {str(e)}") # Логируем ошибку return jsonify({"status": "error", "message": str(e)}), 500 @app.route('/delete_imported_data', methods=['POST']) def delete_imported_data(): try: current_date = datetime.now().date().strftime("%Y-%m-%d") rows_deleted = TableRow.query.filter_by(date=current_date).delete() db.session.commit() return jsonify({"status": "success", "message": f"{rows_deleted} rows deleted for date {current_date}"}) except Exception as e: db.session.rollback() return jsonify({"status": "error", "message": str(e)}), 500 @app.route('/get_rpa_records', methods=['GET']) def get_rpa_records(): try: # Замените фильтр по имени 'worker_name' на фильтр по 'arma_type' rows = TableRow.query.filter_by(arma_type='RPA').all() data = [] for row in rows: data.append({ 'id': row.id, 'row_number': row.row_number, 'timestamp': row.timestamp, 'number': row.number, 'serial': row.serial, 'dl_number': row.dl_number, 'worker_name': row.worker_name, 'pack_time': row.pack_time, 'arma_type': row.arma_type, 'dateshipment': row.dateshipment, 'aktshipment': row.aktshipment, 'bad_recovery': row.bad_recovery, }) return jsonify({"status": "success", "data": data}) except Exception as e: return jsonify({"status": "error", "message": str(e)}), 500 @app.route('/export_rpa_excel') def export_rpa_excel(): try: # Начинаем построение запроса с фильтрацией по типу АРМА "RPA" query = TableRow.query.filter_by(arma_type='RPA') rows = query.all() # Создаем DataFrame только с отфильтрованными данными data = [] for row in rows: data.append({ '№': row.row_number, 'Время отправки': row.timestamp, 'Номер': row.number, 'Serial': row.serial, 'Графа': row.dl_number, 'Имя отправителя': row.worker_name, 'Время упаковки': row.pack_time, 'Тип АРМА': row.arma_type, 'Дата отгрузки': row.dateshipment, 'Номер акта': row.aktshipment, 'Bad Recovery': row.bad_recovery, }) if not data: return jsonify({"error": "Нет записей для экспорта с заданными критериями."}), 400 df = pd.DataFrame(data) # Создаем Excel файл output = BytesIO() with pd.ExcelWriter(output, engine='xlsxwriter') as writer: df.to_excel(writer, index=False, sheet_name='Sheet1') # Настраиваем форматирование workbook = writer.book worksheet = writer.sheets['Sheet1'] # Автоматическая ширина столбцов for idx, col in enumerate(df.columns): series = df[col] max_len = max( series.astype(str).map(len).max(), len(str(col)) ) + 2 worksheet.set_column(idx, idx, max_len) output.seek(0) return send_file( output, mimetype='application/vnd.openxmlformats-officedocument.spreadsheetml.sheet', as_attachment=True, download_name='RPA_export.xlsx' ) except Exception as e: print(f"Export error: {str(e)}") return jsonify({"error": str(e)}), 500 @app.route('/get_duplicates') def get_duplicates(): try: # Получим все строки из таблицы только с типом "RPA" rows = TableRow.query.filter_by(arma_type='RPA').all() # Хранилища для множества значений numbers = {} serials = {} dl_numbers = {} # Собираем все значения и их индексы data = [] f